import { useQuery, useQueryClient } from "@tanstack/react-query";
import { useCallback } from "react";
import { authClient } from "../lib/auth-client";

export const USER_INVITATIONS_KEY = ["user-invitations"] as const;

export function useUserInvitations() {
	const queryClient = useQueryClient();

	const { data, isLoading } = useQuery({
		queryKey: USER_INVITATIONS_KEY,
		queryFn: async () => {
			const res = await authClient.organization.listInvitations({
				query: { status: "pending" },
			});
			return res.data ?? [];
		},
	});

	const invitations = data ?? [];

	const invalidate = useCallback(() => {
		queryClient.invalidateQueries({ queryKey: USER_INVITATIONS_KEY });
	}, [queryClient]);

	return { invitations, count: invitations.length, isLoading, invalidate };
}

import {
	AlertCircle,
	BookOpen,
	Building2,
	Check,
	ChevronsLeft,
	ChevronsRight,
	ChevronsUpDown,
	Clock,
	DollarSign,
	FolderKanban,
	LayoutDashboard,
	LogOut,
	Plus,
	Settings,
	UserCircle,
} from "lucide-react";
import { useTheme } from "next-themes";
import { useState } from "react";
import { Link, useLocation } from "react-router-dom";
import { useOrganization } from "../../contexts/OrganizationContext";
import { authClient, signOut } from "../../lib/auth-client";
import { cn } from "../../lib/utils";
import { Avatar, AvatarFallback, AvatarImage } from "../ui/avatar";
import {
	DropdownMenu,
	DropdownMenuContent,
	DropdownMenuItem,
	DropdownMenuSeparator,
	DropdownMenuTrigger,
} from "../ui/dropdown-menu";
import {
	Tooltip,
	TooltipContent,
	TooltipProvider,
	TooltipTrigger,
} from "../ui/tooltip";
import { ThemeToggle } from "./ThemeToggle";

const navigation = [
	{ name: "Overview", href: "/dashboard", icon: LayoutDashboard },
	{ name: "Developers", href: "/dashboard/developers", icon: UserCircle },
	{ name: "Projects", href: "/dashboard/projects", icon: FolderKanban },
	{
		name: "ROI & Business Value",
		href: "/dashboard/roi",
		icon: DollarSign,
	},
	{ name: "Sessions", href: "/dashboard/sessions", icon: Clock },
	{ name: "Learnings", href: "/dashboard/learnings", icon: BookOpen },
	{ name: "Errors", href: "/dashboard/errors", icon: AlertCircle },
];

function getInitials(name: string) {
	return name
		.split(" ")
		.map((part) => part[0])
		.join("")
		.toUpperCase()
		.slice(0, 2);
}

function OrgSwitcher({ collapsed }: { collapsed: boolean }) {
	const { activeOrg, organizations, switchOrg } = useOrganization();

	const handleSelect = async (orgId: string) => {
		if (orgId !== activeOrg?.id) {
			await switchOrg(orgId);
		}
	};

	return (
		<DropdownMenu>
			<DropdownMenuTrigger asChild>
				<button
					type="button"
					className={cn(
						"flex w-full items-center gap-1.5 px-4 h-10 overflow-hidden hover:bg-hover transition-colors",
						collapsed && "justify-center px-0",
					)}
				>
					<Building2 className="h-4 w-4 shrink-0 text-accent" />
					{!collapsed && (
						<>
							<span className="flex-1 truncate text-left text-sm font-bold text-heading">
								{activeOrg?.name ?? "Select org"}
							</span>
							<ChevronsUpDown className="h-3.5 w-3.5 shrink-0 text-muted" />
						</>
					)}
				</button>
			</DropdownMenuTrigger>
			<DropdownMenuContent
				side={collapsed ? "right" : "bottom"}
				align="start"
				className="w-56"
			>
				{organizations.map((org) => (
					<DropdownMenuItem key={org.id} onClick={() => handleSelect(org.id)}>
						<Building2 className="h-3.5 w-3.5 shrink-0 text-muted" />
						<span className="flex-1 truncate">{org.name}</span>
						{org.id === activeOrg?.id && (
							<Check className="h-3.5 w-3.5 shrink-0 text-accent" />
						)}
					</DropdownMenuItem>
				))}
				<DropdownMenuSeparator />
				<DropdownMenuItem asChild>
					<Link to="/dashboard/organization">
						<Settings className="h-3.5 w-3.5 shrink-0" />
						<span>Manage organization</span>
					</Link>
				</DropdownMenuItem>
				<DropdownMenuItem asChild>
					<Link to="/dashboard/organization/new">
						<Plus className="h-3.5 w-3.5 shrink-0" />
						<span>Create organization</span>
					</Link>
				</DropdownMenuItem>
			</DropdownMenuContent>
		</DropdownMenu>
	);
}

export function Sidebar() {
	const { pathname } = useLocation();
	const { data: session } = authClient.useSession();
	const [collapsed, setCollapsed] = useState(false);
	const { resolvedTheme } = useTheme();

	const logoSrc =
		resolvedTheme === "dark" ? "/logo-light.svg" : "/logo-dark.svg";

	return (
		<TooltipProvider>
			<div
				className={cn(
					"relative flex h-full shrink-0 flex-col bg-surface border-r border-border z-20 transition-[width] duration-200 ease-in-out",
					collapsed ? "w-14" : "w-64",
				)}
			>
				<div className="flex items-center border-b border-border">
					<Link
						to="/dashboard"
						className={cn(
							"flex items-center shrink-0 px-4 h-10",
							collapsed && "px-3",
						)}
					>
						<img src={logoSrc} alt="Rudel" className="h-5 w-5" />
					</Link>
					<div className="flex-1 min-w-0">
						<OrgSwitcher collapsed={collapsed} />
					</div>
					<button
						type="button"
						onClick={() => setCollapsed(!collapsed)}
						className="p-1 mr-1 rounded-md text-muted hover:text-foreground hover:bg-hover transition-colors shrink-0"
						title={collapsed ? "Expand sidebar" : "Collapse sidebar"}
					>
						{collapsed ? (
							<ChevronsRight className="h-4 w-4" />
						) : (
							<ChevronsLeft className="h-4 w-4" />
						)}
					</button>
				</div>

				<nav className="flex-1 px-2 pt-2 pb-1 flex flex-col gap-[1px]">
					{navigation.map((item) => {
						const isActive = pathname === item.href;
						const Icon = item.icon;

						const link = (
							<Link
								to={item.href}
								className={cn(
									"flex items-center gap-2 rounded-lg px-2 py-2 text-[0.8125rem] font-medium transition-colors duration-150",
									collapsed && "justify-center",
									isActive
										? "bg-hover text-heading"
										: "text-muted hover:bg-hover hover:text-foreground",
								)}
							>
								<Icon className="h-4 w-4 shrink-0" />
								{!collapsed && (
									<span className="whitespace-nowrap overflow-hidden">
										{item.name}
									</span>
								)}
							</Link>
						);

						return (
							<div key={item.name}>
								{collapsed ? (
									<Tooltip>
										<TooltipTrigger asChild>{link}</TooltipTrigger>
										<TooltipContent side="right">{item.name}</TooltipContent>
									</Tooltip>
								) : (
									link
								)}
							</div>
						);
					})}
				</nav>

				{session?.user && (
					<div
						className={cn(
							"border-t border-border p-2 flex items-center gap-2",
							collapsed ? "justify-center" : "px-2",
						)}
					>
						{collapsed ? (
							<Tooltip>
								<TooltipTrigger asChild>
									<Link
										to="/dashboard/profile"
										className="flex items-center gap-2 min-w-0"
									>
										<Avatar size="sm" className="shrink-0">
											{session.user.image && (
												<AvatarImage
													src={session.user.image}
													alt={session.user.name}
												/>
											)}
											<AvatarFallback>
												{getInitials(session.user.name)}
											</AvatarFallback>
										</Avatar>
									</Link>
								</TooltipTrigger>
								<TooltipContent side="right">
									{session.user.name}
								</TooltipContent>
							</Tooltip>
						) : (
							<>
								<Link
									to="/dashboard/profile"
									className="flex-1 flex items-center gap-2 min-w-0"
								>
									<Avatar size="sm" className="shrink-0">
										{session.user.image && (
											<AvatarImage
												src={session.user.image}
												alt={session.user.name}
											/>
										)}
										<AvatarFallback>
											{getInitials(session.user.name)}
										</AvatarFallback>
									</Avatar>
									<span className="flex-1 truncate text-xs font-medium text-foreground hover:text-heading transition-colors">
										{session.user.name}
									</span>
								</Link>
								<ThemeToggle />
								<button
									type="button"
									onClick={() => signOut()}
									className="p-1 rounded-md text-muted hover:text-foreground hover:bg-hover transition-colors shrink-0"
									title="Sign out"
								>
									<LogOut className="h-3.5 w-3.5" />
								</button>
							</>
						)}
					</div>
				)}
			</div>
		</TooltipProvider>
	);
}

