				path="/"
				element={<Navigate to={getValidRedirect() || "/dashboard"} replace />}
			/>
			<Route
				path="/invitation/:invitationId"
				element={<AcceptInvitationPage />}
			/>
			<Route path="/dashboard" element={<DashboardLayout />}>
